Real64 DayltgGlarePositionFactor(Real64 X, // Lateral and vertical distance of luminous window element from
                                 Real64 Y)
{

    // SUBROUTINE INFORMATION:
    //       AUTHOR         Fred Winkelmann
    //       DATE WRITTEN   July 1997

    // PURPOSE OF THIS SUBROUTINE:
    // by table interpolation, evaluates the
    // Hopkinson position factor used in glare calculation
    // (Hopkinson, Petherbridge, AND Longmore -- Daylighting,
    // London, 1966, PP 307, 323).  X (Y) is the lateral
    // (vertical) distance of luminous window element from
    // horizontal line of vision, divided by horizontal distance
    // from eye of observer. The array PF contains values of
    // the position factor for X = 0, 0.5, 1.0, 1.5, 2.0, 2.5,
    // and 3.0 and Y = 0, 0.5, 1.0, 1.5, 2.0. Called by CalcDayltgCoefficients.

    // REFERENCES:
    // Based on DOE-2.1E subroutine DPFAC.

    // Position factor array
    static constexpr std::array<std::array<Real64, 7>, 5> PF = {{
        {1.00, 0.492, 0.226, 0.128, 0.081, 0.061, 0.057},
        {0.123, 0.119, 0.065, 0.043, 0.029, 0.026, 0.023},
        {0.019, 0.026, 0.019, 0.016, 0.014, 0.011, 0.011},
        {0.008, 0.008, 0.008, 0.008, 0.008, 0.006, 0.006},
        {0.0, 0.0, 0.003, 0.003, 0.003, 0.003, 0.003},
    }};

    if (X < 0.0 || X >= 3.0) {
        return 0.0;
    }
    if (Y < 0.0 || Y >= 2.0) {
        return 0.0;
    }

    int IX = 1 + int(2.0 * X);
    int IY = 1 + int(2.0 * Y);
    Real64 X1 = 0.5 * double(IX - 1);
    Real64 Y1 = 0.5 * double(IY - 1);
    Real64 FA = PF[IY - 1][IX - 1] + 2.0 * (X - X1) * (PF[IY - 1][IX] - PF[IY - 1][IX - 1]);
    Real64 FB = PF[IY][IX - 1] + 2.0 * (X - X1) * (PF[IY][IX] - PF[IY][IX - 1]);
    return FA + 2.0 * (Y - Y1) * (FB - FA);
}

Real64 pvstar(Real64 const T)
    {
        // Thermodynamic parameters
        constexpr Real64 Ttrip = 273.16; // K
        constexpr Real64 ptrip = 611.65; // Pa
        constexpr Real64 E0v = 2.3740e6; // J/kg
        constexpr Real64 E0s = 0.3337e6; // J/kg
        // constexpr Real64 rgasa = 287.04; // J/kg/K
        constexpr Real64 rgasv = 461.; // J/kg/K
        // constexpr Real64 cva = 719.;     // J/kg/K
        constexpr Real64 cvv = 1418.; // J/kg/K
        constexpr Real64 cvl = 4119.; // J/kg/K
        constexpr Real64 cvs = 1861.; // J/kg/K
        // constexpr Real64 cpa = cva + rgasa;
        constexpr Real64 cpv = cvv + rgasv;

        if (T == 0.0) {
            return 0.0;
        }
        if (T < Ttrip) {
            return ptrip * pow((T / Ttrip), ((cpv - cvs) / rgasv)) * exp((E0v + E0s - (cvv - cvs) * Ttrip) / rgasv * (1. / Ttrip - 1. / T));
        }
        return ptrip * pow((T / Ttrip), ((cpv - cvl) / rgasv)) * exp((E0v - (cvv - cvl) * Ttrip) / rgasv * (1. / Ttrip - 1. / T));

        return 0.0;
    }

int OrdinalDay(int const Month,        // Month, 1..12
               int const Day,          // Day of Month, not validated by month
               int const LeapYearValue // 1 if leap year indicated, 0 if not
)
{

    // FUNCTION INFORMATION:
    //       AUTHOR         Linda K. Lawrie
    //       DATE WRITTEN   September 1997
    //       RE-ENGINEERED  from JDAYF in BLAST/IBLAST

    // PURPOSE OF THIS SUBROUTINE:
    // This subroutine returns the appropriate Julian Day value for the input
    // Month and Day.

    // SUBROUTINE LOCAL VARIABLE DECLARATIONS:
    static constexpr std::array<int, 12> EndDayofMonth = {31, 59, 90, 120, 151, 181, 212, 243, 273, 304, 334, 365};
    // End day numbers of each month (without Leap Year)

    if (Month == 1) {
        //                                       CASE 1: JANUARY
        return Day;
    }
    if (Month == 2) {
        //                                       CASE 2: FEBRUARY
        return Day + EndDayofMonth[0];
    }
    if ((Month >= 3) && (Month <= 12)) {
        //                                       CASE 3: REMAINING MONTHS
        return Day + EndDayofMonth[Month - 2] + LeapYearValue;
    }
    return 0;
}

bool BBConvergeCheck(int const SimCompNum, Real64 const MaxFlow, Real64 const MinFlow)
{

    // FUNCTION INFORMATION:
    //       AUTHOR         Rick Strand
    //       DATE WRITTEN   November 2017

    // PURPOSE OF THIS SUBROUTINE:
    // This is an additional check for the radiant/convective baseboard units
    // to see if they are converged or the flow is sufficiently converged to
    // procede with the simulation.  With the radiant component to these systems,
    // the impact on the load met is more difficult to calculate and the impact
    // on the actual system output is not as well behaved as for convective
    // systems.  This additional check avoids excessive iterations and max
    // iteration warnings and provides sufficiently converged results.  It is
    // only called from ControlCompOutput.

    // Return Value
    bool BBConvergeCheck;

    // SUBROUTINE PARAMETER DEFINITIONS:
    static Real64 constexpr BBIterLimit = 0.00001;

    if (SimCompNum != BBSteamRadConvNum && SimCompNum != BBWaterRadConvNum) {
        // For all zone equipment except radiant/convective baseboard (steam and water) units:
        BBConvergeCheck = false;
    } else {
        // For steam and water radiant/convective baseboard units:
        if ((MaxFlow - MinFlow) > BBIterLimit) {
            BBConvergeCheck = false;
        } else {
            BBConvergeCheck = true;
        }
    }

    return BBConvergeCheck;
}

