                          Real64 LowerBound,  // RoomAirPattern(PattrnID).TwoGradPatrn.LowerBoundTempScale
                          Real64 LowGradient  // RoomAirPattern(PattrnID).TwoGradPatrn.LowGradient
)
{
    if (DryBulbTemp >= UpperBound) {
